#include <bits/stdc++.h>
using namespace std;int n,m;vector<int>cur;vector<bool>used;string o;
void bt(){if((int)cur.size()==m){for(int i=0;i<m;i++){o+=to_string(cur[i]);o+=(i+1<m?' ':'\n');}return;}for(int i=1;i<=n;i++)if(!used[i]){used[i]=1;cur.push_back(i);bt();cur.pop_back();used[i]=0;}}
int main(){cin>>n>>m;used.assign(n+1,false);bt();cout<<o;}
